pub const unsafe fn encode_utf8_raw_unchecked(code: u32, dst: *mut u8) {
    let len = len_utf8(code);
    // SAFETY: The caller must guarantee that the buffer pointed to by `dst`
    // is at least `len` bytes long.
    unsafe {
        if len == 1 {
            *dst = code as u8;
            return;
        }

        let last1 = (code >> 0 & 0x3F) as u8 | TAG_CONT;
        let last2 = (code >> 6 & 0x3F) as u8 | TAG_CONT;
        let last3 = (code >> 12 & 0x3F) as u8 | TAG_CONT;
        let last4 = (code >> 18 & 0x3F) as u8 | TAG_FOUR_B;

        if len == 2 {
            *dst = last2 | TAG_TWO_B;
            *dst.add(1) = last1;
            return;
        }

        if len == 3 {
            *dst = last3 | TAG_THREE_B;
            *dst.add(1) = last2;
            *dst.add(2) = last1;
            return;
        }

        *dst = last4;
        *dst.add(1) = last3;
        *dst.add(2) = last2;
        *dst.add(3) = last1;
    }
}

pub unsafe fn slice_unchecked(&self, begin: usize, end: usize) -> &str {
    // SAFETY: the caller must uphold the safety contract for `get_unchecked`;
    // the slice is dereferenceable because `self` is a safe reference.
    // The returned pointer is safe because impls of `SliceIndex` have to guarantee that it is.
    unsafe { &*(begin..end).get_unchecked(self) }
}

pub unsafe fn slice_mut_unchecked(&mut self, begin: usize, end: usize) -> &mut str {
    // SAFETY: the caller must uphold the safety contract for `get_unchecked_mut`;
    // the slice is dereferenceable because `self` is a safe reference.
    // The returned pointer is safe because impls of `SliceIndex` have to guarantee that it is.
    unsafe { &mut *(begin..end).get_unchecked_mut(self) }
}

pub unsafe fn from_vec_unchecked(v: Vec<u8>) -> Self {
    debug_assert!(memchr::memchr(0, &v).is_none());
    unsafe { Self::_from_vec_unchecked(v) }
}

pub unsafe fn from_boxed_utf8_unchecked(v: Box<[u8]>) -> Box<str> {
    unsafe { Box::from_raw(Box::into_raw(v) as *mut str) }
}

pub unsafe fn from_encoded_bytes_unchecked(bytes: Vec<u8>) -> Self {
    OsString { inner: unsafe { Buf::from_encoded_bytes_unchecked(bytes) } }
}

pub const unsafe fn as_ref_unchecked(&self) -> &T {
    // SAFETY: pointer comes from `&self` so naturally satisfies ptr-to-ref invariants.
    unsafe { self.get().as_ref_unchecked() }
}

pub const unsafe fn as_mut_unchecked(&self) -> &mut T {
    // SAFETY: pointer comes from `&self` so naturally satisfies ptr-to-ref invariants.
    unsafe { self.get().as_mut_unchecked() }
}

pub const fn get_mut_unchecked(&mut self) -> *mut T {
    ptr::from_mut(self) as *mut T
}

pub const unsafe fn unreachable_unchecked() -> ! {
    ub_checks::assert_unsafe_precondition!(
        check_language_ub,
        "hint::unreachable_unchecked must never be reached",
        () => false
    );
    // SAFETY: the safety contract for `intrinsics::unreachable` must
    // be upheld by the caller.
    unsafe { intrinsics::unreachable() }
}

pub const unsafe fn assert_unchecked(cond: bool) {
    // SAFETY: The caller promised `cond` is true.
    unsafe {
        ub_checks::assert_unsafe_precondition!(
            check_language_ub,
            "hint::assert_unchecked must never be called when the condition is false",
            (cond: bool = cond) => cond,
        );
        crate::intrinsics::assume(cond);
    }
}
